import { Component, OnInit, OnDestroy, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ActivatedRoute, Router, RouterModule } from '@angular/router';
import { FormsModule } from '@angular/forms';
import { Subject, lastValueFrom, takeUntil } from 'rxjs';

import { AuthService } from '../../services/timbrature-auth.adapter';
import { UsersService } from '../../services/user.service';
import { TimbratureService } from '../../services/timbrature.service';
import { DepartmentsService } from '../../services/departments.service';
import { JobTitlesService } from '../../services/jobtitle.service';
import { CompanyService } from '../../services/company.service';

import { User, Department, JobTitle, Timbratura } from '../../models';
import { LUCIDE_ICONS, LucideAngularModule } from 'lucide-angular';

interface StatisticheDipendente {
  oreLavorate: number;
  giorniPresenti: number;
  mediaOreGiornaliere: number;
  puntualita: number; // da definire meglio
}

@Component({
  selector: 'app-dipendente-dettaglio',
  standalone: true,
  imports: [CommonModule, RouterModule, FormsModule, LucideAngularModule],
  templateUrl: './dipendente-dettaglio.component.html',
  styleUrls: ['./dipendente-dettaglio.component.css']
})
export class DipendenteDettaglioComponent implements OnInit, OnDestroy {
  private route = inject(ActivatedRoute);
  private router = inject(Router);
  private authService = inject(AuthService);
  private usersService = inject(UsersService);
  private timbratureService = inject(TimbratureService);
  private departmentsService = inject(DepartmentsService);
  private jobTitlesService = inject(JobTitlesService);
  private companyService = inject(CompanyService);

  isLoading = true;
  dipendente: User | null = null;
  timbratureRecenti: Timbratura[] = [];
  statistiche: StatisticheDipendente = {
    oreLavorate: 0,
    giorniPresenti: 0,
    mediaOreGiornaliere: 0,
    puntualita: 0
  };
  andamentoSettimanale: { giorno: string; ore: number }[] = [];

  // Reparti e mansioni
  departments: Department[] = [];
  jobTitles: JobTitle[] = [];
  isLoadingJobTitles = false;

  // Stato UI per editing
  editingWorkInfo = false;
  editWorkModel: Partial<User> = {};

  // Messaggi
  messaggioSuccesso = '';
  messaggioErrore = '';

  private destroy$ = new Subject<void>();

  ngOnInit() {
    const id = this.route.snapshot.paramMap.get('id');
    if (!id) {
      this.router.navigate(['/dipendenti']);
      return;
    }

    this.authService.currentUser$
      .pipe(takeUntil(this.destroy$))
      .subscribe(async (currentUser) => {
        if (!currentUser) {
          this.router.navigate(['/login']);
          return;
        }

        // Controllo permessi per manager
        if (this.authService.hasRole('manager')) {
          const canEdit = await this.checkManagerPermission(currentUser);
          if (!canEdit) {
            alert('Non hai i permessi per accedere al dettaglio dipendente.');
            this.router.navigate(['/dipendenti']);
            return;
          }
        }

        await this.loadDipendenteAndData(id);
      });
  }

  ngOnDestroy() {
    this.destroy$.next();
    this.destroy$.complete();
  }

  private async checkManagerPermission(manager: User): Promise<boolean> {
    try {
      const company = await lastValueFrom(
        this.companyService.getForUser(manager.id, manager.company_id)
      );
      const config = this.companyService.resolveManagerConfig(company, manager.id);
      return config.can_edit_employees ?? false;
    } catch {
      return false;
    }
  }

  private async loadDipendenteAndData(id: string) {
    this.isLoading = true;
    try {
      // Carica dipendente
      const user = await lastValueFrom(this.usersService.getById(id));
      if (!user) {
        this.router.navigate(['/dipendenti']);
        return;
      }
      this.dipendente = user;

      // Carica reparti e mansioni dell'azienda
      if (user.company_id) {
        await Promise.all([
          this.loadDepartments(user.company_id),
          this.loadJobTitles(user.company_id)
        ]);
      }

      // Carica timbrature recenti, statistiche e andamento in parallelo
      await Promise.all([
        this.loadTimbratureRecenti(user.id),
        this.loadStatistiche(user.id),
        this.loadAndamentoSettimanale(user.id)
      ]);
    } catch (error) {
      console.error('Errore caricamento dipendente', error);
      this.messaggioErrore = 'Errore nel caricamento dei dati';
      this.nascondiMessaggioDopoTimeout();
    } finally {
      this.isLoading = false;
    }
  }

  private async loadDepartments(companyId: string) {
    try {
      this.departments = await lastValueFrom(
        this.departmentsService.getByCompany(companyId)
      );
    } catch (error) {
      console.error('Errore caricamento reparti', error);
      this.departments = [];
    }
  }

  private async loadJobTitles(companyId: string) {
    this.isLoadingJobTitles = true;
    try {
      this.jobTitles = await lastValueFrom(
        this.jobTitlesService.getByCompany(companyId)
      );
    } catch (error) {
      console.error('Errore caricamento mansioni', error);
      this.jobTitles = [];
    } finally {
      this.isLoadingJobTitles = false;
    }
  }

  private async loadTimbratureRecenti(userId: string) {
    try {
      const timbrature = await lastValueFrom(
        this.timbratureService.getFiltered({
          company_id: this.dipendente!.company_id!,
          user_id: userId
        })
      );
      // Ordina per data decrescente e prendi le ultime 10
      this.timbratureRecenti = timbrature
        .sort((a, b) => new Date(b.start_ts).getTime() - new Date(a.start_ts).getTime())
        .slice(0, 10);
    } catch (error) {
      console.error('Errore caricamento timbrature recenti', error);
      this.timbratureRecenti = [];
    }
  }

  private async loadStatistiche(userId: string) {
    try {
      const oggi = new Date();
      const inizioMese = new Date(oggi.getFullYear(), oggi.getMonth(), 1);
      const inizioProssimoMese = new Date(oggi.getFullYear(), oggi.getMonth() + 1, 1);

      const timbratureMese = await lastValueFrom(
        this.timbratureService.getFiltered({
          company_id: this.dipendente!.company_id!,
          user_id: userId,
          start_ts: {
            gte: inizioMese.toISOString(),
            lt: inizioProssimoMese.toISOString()
          }
        })
      );

      const oreTotali = timbratureMese.reduce((acc, t) => acc + (t.total_minutes || 0) / 60, 0);
      const giorniUnici = new Set(
        timbratureMese.map(t => new Date(t.start_ts).toISOString().slice(0, 10))
      ).size;

      this.statistiche = {
        oreLavorate: oreTotali,
        giorniPresenti: giorniUnici,
        mediaOreGiornaliere: giorniUnici > 0 ? oreTotali / giorniUnici : 0,
        puntualita: 0 // da implementare se serve
      };
    } catch (error) {
      console.error('Errore caricamento statistiche', error);
    }
  }

  private async loadAndamentoSettimanale(userId: string) {
    const labels = ['Lun', 'Mar', 'Mer', 'Gio', 'Ven', 'Sab', 'Dom'];
    try {
      const oggi = new Date();
      const day = (oggi.getDay() + 6) % 7; // 0 = lunedì
      const inizioSettimana = new Date(oggi);
      inizioSettimana.setHours(0, 0, 0, 0);
      inizioSettimana.setDate(inizioSettimana.getDate() - day);
      const fineSettimana = new Date(inizioSettimana);
      fineSettimana.setDate(inizioSettimana.getDate() + 7);

      const timbratureSettimana = await lastValueFrom(
        this.timbratureService.getFiltered({
          company_id: this.dipendente!.company_id!,
          user_id: userId,
          start_ts: {
            gte: inizioSettimana.toISOString(),
            lt: fineSettimana.toISOString()
          }
        })
      );

      const risultato: { giorno: string; ore: number }[] = [];

      for (let i = 0; i < 7; i++) {
        const giorno = new Date(inizioSettimana);
        giorno.setDate(inizioSettimana.getDate() + i);
        const giornoSuccessivo = new Date(giorno);
        giornoSuccessivo.setDate(giorno.getDate() + 1);

        const oreGiorno = timbratureSettimana
          .filter(t => {
            const ts = new Date(t.start_ts);
            return ts >= giorno && ts < giornoSuccessivo;
          })
          .reduce((acc, t) => acc + (t.total_minutes || 0) / 60, 0);

        risultato.push({
          giorno: labels[i],
          ore: Math.round(oreGiorno * 10) / 10
        });
      }

      this.andamentoSettimanale = risultato;
    } catch (error) {
      console.error('Errore caricamento andamento settimanale', error);
      this.andamentoSettimanale = labels.map(g => ({ giorno: g, ore: 0 }));
    }
  }

  // --- Metodi per l'editing ---
  beginEditWorkInfo() {
    if (!this.dipendente) return;
    this.editWorkModel = {
      first_name: this.dipendente.first_name,
      last_name: this.dipendente.last_name,
      birth_place: this.dipendente.birth_place,
      hire_date: this.dipendente.hire_date,
      department_id: this.dipendente.department_id,
      job_title_id: this.dipendente.job_title_id,
      job_title: this.dipendente.job_title,
      role: this.dipendente.role,
      is_active: this.dipendente.is_active,
      full_time: this.dipendente.full_time,
      monthly_hours: this.dipendente.monthly_hours
    };
    this.editingWorkInfo = true;
  }

  cancelEditWorkInfo() {
    this.editingWorkInfo = false;
    this.editWorkModel = {};
  }

  async onSaveWorkInfo() {
    if (!this.dipendente?.id) return;
    this.isLoading = true;

    try {
      // Gestione creazione nuova mansione se "__altro"
      if (this.editWorkModel.job_title_id === '__altro' && this.editWorkModel.job_title?.trim()) {
        if (!this.authService.hasRole('admin')) {
          this.editWorkModel.job_title_id = null;
        } else {
          const newTitle = await lastValueFrom(
            this.jobTitlesService.create({
              company_id: this.dipendente.company_id!,
              name: this.editWorkModel.job_title.trim(),
              is_active: true,
              created_by: this.authService.currentUserSubject.value!.id
            } as JobTitle)
          );
          this.jobTitles = [newTitle, ...this.jobTitles];
          this.editWorkModel.job_title_id = newTitle.id;
          this.editWorkModel.job_title = newTitle.name;
        }
      }

      // Costruzione payload pulito
      const payload: Partial<User> = {
        first_name: this.editWorkModel.first_name,
        last_name: this.editWorkModel.last_name,
        birth_place: this.editWorkModel.birth_place,
        hire_date: this.editWorkModel.hire_date,
        department_id: this.editWorkModel.department_id === '__none' ? null : this.editWorkModel.department_id,
        job_title_id: this.editWorkModel.job_title_id === '__altro' ? null : this.editWorkModel.job_title_id,
        job_title: this.editWorkModel.job_title,
        role: this.editWorkModel.role,
        is_active: this.editWorkModel.is_active,
        full_time: this.editWorkModel.full_time,
        monthly_hours: this.editWorkModel.monthly_hours ? Number(this.editWorkModel.monthly_hours) : null
      };

      // Rimuovi undefined
      Object.keys(payload).forEach(key => payload[key as keyof User] === undefined && delete payload[key as keyof User]);

      const updated = await lastValueFrom(
        this.usersService.update(this.dipendente.id, payload, this.dipendente.company_id ?? undefined)
      );
      this.dipendente = { ...this.dipendente, ...updated };
      this.editingWorkInfo = false;
      this.messaggioSuccesso = 'Informazioni aggiornate con successo';
      this.nascondiMessaggioDopoTimeout();
    } catch (error) {
      console.error('Errore salvataggio', error);
      this.messaggioErrore = 'Errore durante il salvataggio';
      this.nascondiMessaggioDopoTimeout();
    } finally {
      this.isLoading = false;
    }
  }

  // --- Metodi di utilità ---
  nascondiMessaggioDopoTimeout() {
    setTimeout(() => {
      this.messaggioSuccesso = '';
      this.messaggioErrore = '';
    }, 5000);
  }

  getRuoloLabel(role?: string): string {
    const map: Record<string, string> = {
      admin: 'Amministratore',
      manager: 'Manager',
      employee: 'Dipendente'
    };
    return role ? map[role] || role : 'Dipendente';
  }

  getDifferenzaOre(): number {
    const previste = this.dipendente?.monthly_hours || 0;
    const lavorate = this.statistiche.oreLavorate;
    return lavorate - previste;
  }

  getClasseDifferenzaOre(): string {
    return this.getDifferenzaOre() >= 0 ? 'positive' : 'negative';
  }

  getPercentualeCompletamento(): number {
    const previste = this.dipendente?.monthly_hours || 0;
    const lavorate = this.statistiche.oreLavorate;
    return previste > 0 ? lavorate / previste : 0;
  }

  getAltezzaBarra(ore: number): number {
    const max = Math.max(...this.andamentoSettimanale.map(item => item.ore), 0.1);
    return (ore / max) * 100;
  }

vediTutteTimbrature() {
  if (this.dipendente) {
    this.router.navigate(['/restaurant/timbrature/lista'], 
      { queryParams: { dipendente: this.dipendente.id } });
  }
}

modificaTimbratura(timbratura: Timbratura) {
  this.router.navigate(['/restaurant/timbrature/crea'], 
    { queryParams: { edit: timbratura.id, mode: 'edit' } });
}

trackById(index: number, item: any) {
  return item.id;
}


  eliminaTimbratura(timbratura: Timbratura) {
    if (!confirm('Sei sicuro di voler eliminare questa timbratura?')) return;
    // Qui chiameremmo il servizio per soft delete, ma è già presente nel componente lista-timbrature
    // Per ora rimuoviamo solo dalla lista locale
    this.timbratureRecenti = this.timbratureRecenti.filter(t => t.id !== timbratura.id);
  }

  generaReport() {
    const content = `
      REPORT DIPENDENTE
      =================
      
      Nome: ${this.dipendente?.first_name} ${this.dipendente?.last_name}
      Email: ${this.dipendente?.email}
      Mansione: ${this.dipendente?.job_title}
      Reparto: ${this.getDepartmentName()}
      
      STATISTICHE MENSILI
      -------------------
      Ore lavorate: ${this.statistiche.oreLavorate.toFixed(1)}
      Giorni presenti: ${this.statistiche.giorniPresenti}
      Media ore/giorno: ${this.statistiche.mediaOreGiornaliere.toFixed(1)}
      Puntualità: ${(this.statistiche.puntualita * 100).toFixed(1)}%
    `;

    const blob = new Blob([content], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `report_${this.dipendente?.first_name}_${this.dipendente?.last_name}.txt`;
    a.click();
    URL.revokeObjectURL(url);
  }

  getDepartmentName(): string {
    if (!this.dipendente?.department_id) return 'Nessun reparto';
    const dept = this.departments.find(d => d.id === this.dipendente?.department_id);
    return dept?.name || 'Nessun reparto';
  }

  hasRole(role: string): boolean {
    return this.authService.hasRole(role);
  }

  get editingDepartment(): boolean {
    return this.editingWorkInfo;
  }

  get isAdmin(): boolean { return this.authService.hasRole('admin'); }
get isManager(): boolean { return this.authService.hasRole('manager'); }
get isEmployee(): boolean { return this.authService.hasRole('employee'); }

}
